+import { type AnyColumn, Column } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type WindowValue<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+
+export type WindowOrderBy = SQLWrapper;
+
+type FrameBoundaryKind = 'unboundedPreceding' | 'preceding' | 'currentRow' | 'following' | 'unboundedFollowing';
+
+export interface FrameBoundary {
+	readonly kind: FrameBoundaryKind;
+	readonly value?: number;
+}
+
+export const unboundedPreceding: FrameBoundary = { kind: 'unboundedPreceding' };
+export const currentRow: FrameBoundary = { kind: 'currentRow' };
+export const unboundedFollowing: FrameBoundary = { kind: 'unboundedFollowing' };
+
+function positionalBoundary(name: 'preceding' | 'following', value: number): FrameBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	}
+	return { kind: name, value };
+}
+
+export function preceding(value: number): FrameBoundary {
+	return positionalBoundary('preceding', value);
+}
+
+export function following(value: number): FrameBoundary {
+	return positionalBoundary('following', value);
+}
+
+export interface WindowFrame {
+	readonly mode: 'rows' | 'range';
+	readonly from: FrameBoundary;
+	readonly to: FrameBoundary;
+}
+
+export interface WindowFrameSpec {
+	from: FrameBoundary;
+	to: FrameBoundary;
+}
+
+function boundaryPosition(boundary: FrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unboundedPreceding': return Number.NEGATIVE_INFINITY;
+		case 'preceding': return -boundary.value!;
+		case 'currentRow': return 0;
+		case 'following': return boundary.value!;
+		case 'unboundedFollowing': return Number.POSITIVE_INFINITY;
+	}
+}
+
+function frame(mode: WindowFrame['mode'], spec: WindowFrameSpec): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	}
+	return { mode, ...spec };
+}
+
+export function rows(spec: WindowFrameSpec): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: WindowFrameSpec): WindowFrame {
+	return frame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: WindowOrderBy | WindowOrderBy[];
+	orderBy?: WindowOrderBy | WindowOrderBy[];
+	frame?: WindowFrame;
+}
+
+function boundarySql(boundary: FrameBoundary): SQL {
+	switch (boundary.kind) {
+		case 'unboundedPreceding': return sql.raw('unbounded preceding');
+		case 'preceding': return sql.raw(`${boundary.value} preceding`);
+		case 'currentRow': return sql.raw('current row');
+		case 'following': return sql.raw(`${boundary.value} following`);
+		case 'unboundedFollowing': return sql.raw('unbounded following');
+	}
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) parts.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	if (spec.orderBy) parts.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	if (spec.frame) parts.push(sql`${sql.raw(spec.frame.mode)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`);
+	return sql.join(parts, sql` `);
+}
+
+export function buildWindowDefinition(name: string, spec: WindowSpec): SQL {
+	return sql`${sql.identifier(name)} as (${buildWindowSpec(spec)})`;
+}
+
+class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positionalArgument(name: 'ntile' | 'nthValue', value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer; received ${value}`);
+	}
+	return sql.raw(String(value));
+}
+
+function nullableValue<T extends SQLWrapper>(name: string, value: T): WindowFunction<WindowValue<T> | null> {
+	return windowFunction(name, [value]);
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function ntile(value: number): WindowFunction<number> { return windowFunction('ntile', [positionalArgument('ntile', value)]); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+
+export function lag<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null>;
+export function lag<T extends SQLWrapper>(value: T, offset: number): WindowFunction<WindowValue<T> | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<WindowValue<T>, null> | WindowValue<TDefault>>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	return windowFunction('lag', [value, ...(offset === undefined ? [] : [sql.raw(String(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+
+export function lead<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null>;
+export function lead<T extends SQLWrapper>(value: T, offset: number): WindowFunction<WindowValue<T> | null>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<WindowValue<T>, null> | WindowValue<TDefault>>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	return windowFunction('lead', [value, ...(offset === undefined ? [] : [sql.raw(String(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null> { return nullableValue('first_value', value); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null> { return nullableValue('last_value', value); }
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowFunction<WindowValue<T> | null> { return windowFunction('nth_value', [value, positionalArgument('nthValue', nth)]); }
+
+export function windowSum(value: SQLWrapper): WindowFunction<string | null> { return windowFunction('sum', [value]); }
+export function windowAvg(value: SQLWrapper): WindowFunction<string | null> { return windowFunction('avg', [value]); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null> { return nullableValue('min', value); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowFunction<WindowValue<T> | null> { return nullableValue('max', value); }
+export function windowCount(value?: SQLWrapper): WindowFunction<number> { return windowFunction('count', [value ?? sql.raw('*')]); }
