+const users = pgTable('users', { id: serial().primaryKey(), score: serial() });
+const dialect = new PgDialect();
+
+test('window helpers emit SQL without positional parameters', () => {
+	const spec = { partitionBy: users.id, orderBy: users.score, frame: rows({ from: unboundedPreceding, to: currentRow }) };
+	const expressions = [
+		rowNumber(), rank(), denseRank(), ntile(2), percentRank(), cumeDist(), lag(users.score, 0), lead(users.score, 1),
+		firstValue(users.score), lastValue(users.score), nthValue(users.score, 3), windowSum(users.score), windowAvg(users.score),
+		windowMin(users.score), windowMax(users.score), windowCount(),
+	].map((expression) => dialect.sqlToQuery(expression.over(spec)));
+
+	expect(expressions.map(({ sql }) => sql)).toEqual([
+		'row_number() over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'rank() over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'dense_rank() over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'ntile(2) over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'percent_rank() over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'cume_dist() over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'lag("users"."score", 0) over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'lead("users"."score", 1) over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'first_value("users"."score") over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'last_value("users"."score") over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'nth_value("users"."score", 3) over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'sum("users"."score") over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'avg("users"."score") over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'min("users"."score") over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'max("users"."score") over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+		'count(*) over (partition by "users"."id" order by "users"."score" rows between unbounded preceding and current row)',
+	]);
+	expect(expressions.every(({ params }) => params.length === 0)).toBe(true);
+});
+
+test('empty, named, and framed windows compile and validate', () => {
+	expect(dialect.sqlToQuery(rowNumber().over({})).sql).toBe('row_number() over ()');
+	expect(dialect.sqlToQuery(rank().over('rank window')).sql).toBe('rank() over "rank window"');
+	expect(new QueryBuilder(dialect).select({ rank: rank().over('w') }).from(users).window('w', { orderBy: users.score }).orderBy(users.id).toSQL().sql)
+		.toBe('select rank() over "w" from "users" window "w" as (order by "users"."score") order by "users"."id"');
+	expect(range({ from: currentRow, to: following(1) }).mode).toBe('range');
+	expect(() => ntile(0)).toThrow(/ntile.*0/);
+	expect(() => nthValue(users.score, 0)).toThrow(/nthValue.*0/);
+	expect(() => rows({ from: currentRow, to: unboundedPreceding })).toThrow(/from/);
+	expect(() => following(-1)).toThrow(/following/);
+	expect(() => new QueryBuilder(dialect).select().from(users).window('', {})).toThrow(/non-empty/);
